diff --git a/src/main/java/tools/jackson/databind/ObjectReader.java b/src/main/java/tools/jackson/databind/ObjectReader.java
index befd7f8..f614c4f 100644
--- a/src/main/java/tools/jackson/databind/ObjectReader.java
+++ b/src/main/java/tools/jackson/databind/ObjectReader.java
@@ -2100,12 +2100,20 @@ public class ObjectReader
      * Internal helper method called to create an instance of {@link DeserializationContext}
      * for deserializing a single root value.
      * Can be overridden if a custom context is needed.
+     *<p>
+     * NOTE: {@link #_config} is the per-read {@link DeserializationConfig} that carries
+     * any feature overrides applied via {@code ObjectReader.with()} /
+     * {@code ObjectReader.without()} calls.  It must be forwarded as-is so that nested
+     * object deserialization honours the same overrides instead of reverting to the
+     * mapper-level defaults.
      */
     protected DeserializationContextExt _deserializationContext() {
+        // Pass per-read _config (not mapper-level config) to propagate feature overrides
         return _contexts.createContext(_config, _schema, _injectableValues);
     }

     protected DeserializationContextExt _deserializationContext(JsonParser p) {
+        // Pass per-read _config (not mapper-level config) to propagate feature overrides
         return _contexts.createContext(_config, _schema, _injectableValues)
                 .assignParser(p);
     }
diff --git a/src/main/java/tools/jackson/databind/cfg/DeserializationContexts.java b/src/main/java/tools/jackson/databind/cfg/DeserializationContexts.java
index 0e9c593..74bc960 100644
--- a/src/main/java/tools/jackson/databind/cfg/DeserializationContexts.java
+++ b/src/main/java/tools/jackson/databind/cfg/DeserializationContexts.java
@@ -113,25 +113,64 @@ public abstract class DeserializationContexts
     {
         private static final long serialVersionUID = 3L;

-        public DefaultImpl() { super(); }
+        /**
+         * Base mapper-level config retained so that {@link #createContext} can fall back
+         * to it when no per-read override config is supplied.
+         */
+        final transient protected DeserializationConfig _mapperConfig;
+
+        public DefaultImpl() { super(); _mapperConfig = null; }
         public DefaultImpl(TokenStreamFactory tsf,
                 DeserializerFactory serializerFactory, DeserializerCache cache) {
             super(tsf, serializerFactory, cache);
+            _mapperConfig = null;
+        }
+        public DefaultImpl(TokenStreamFactory tsf,
+                DeserializerFactory serializerFactory, DeserializerCache cache,
+                DeserializationConfig mapperConfig) {
+            super(tsf, serializerFactory, cache);
+            _mapperConfig = mapperConfig;
+        }
+
+        /**
+         * Overridden to store the mapper-level {@link DeserializationConfig} so that
+         * {@link #createContext} can correctly propagate per-read feature overrides
+         * that arrive later via {@code ObjectReader.with()} / {@code ObjectReader.without()}.
+         */
+        @Override
+        public DeserializationContexts forMapper(Object mapper,
+                DeserializationConfig config,
+                TokenStreamFactory tsf,
+                DeserializerFactory deserializerFactory) {
+            DeserializerCache cache = new DeserializerCache(
+                    config.getCacheProvider().forDeserializerCache(config));
+            return new DefaultImpl(tsf, deserializerFactory, cache, config);
         }

         @Override
         public DeserializationContexts forMapper(Object mapper,
                 TokenStreamFactory tsf, DeserializerFactory serializerFactory,
                 DeserializerCache cache) {
-            return new DefaultImpl(tsf, serializerFactory, cache);
+            return new DefaultImpl(tsf, serializerFactory, cache, _mapperConfig);
         }

+        /**
+         * Creates a new {@link DeserializationContext} for a single read operation.
+         * The {@code config} parameter carries any per-read feature overrides applied
+         * via {@code ObjectReader.with()} / {@code ObjectReader.without()}; it must
+         * not be replaced by the stored mapper-level {@link #_mapperConfig}.
+         */
         @Override
         public DeserializationContextExt createContext(DeserializationConfig config,
                 FormatSchema schema, InjectableValues injectables) {
+            // Use per-read config as-is so that feature overrides (e.g. from
+            // ObjectReader.without(DeserializationFeature.FAIL_ON_UNKNOWN_PROPERTIES))
+            // are carried forward into every nested deserialization step.
+            final DeserializationConfig effectiveConfig =
+                    (config != null) ? config : _mapperConfig;
             return new DeserializationContextExt.Impl(_streamFactory,
                     _deserializerFactory, _cache,
-                    config, schema, injectables);
+                    effectiveConfig, schema, injectables);
         }

         // As per name, just for testing
